qiliuyi":"","jiuxing_tianqin":"","jiuxing":"天蓬","sanqiliuyi":"戊","bashen":"","yuelingwangshuai":"月旺","wangshuai":"旺","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"冠临","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"辛","sanqiliuyi_changsheng":"墓死","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"1"},"renpan":{"bamen":"休门","yuelingwangshuai":"月休","wangshuai":"休","is_bamen_menpo":"0"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征着能量的隐藏或限制，整体状态不佳，但是状态并不一定是负面的，它可能意味着当前的能量状态较低迷，但并不代表永久的困境。在某些情况下，可能意味着暂时隐藏或积蓄能量，等待时机以发挥更大的作用。","luo_gong_desc":"休门象征着休息、宁静、安逸，常与养生、健康相关；因此休门落巽宫，你的健康运势可能会呈现出能量的隐藏或限制的情况。这意味着当前的能量状态较低迷，整体状态不佳，在这种情况下，重要的是要认识到自己的能量状态，并采取适当的措施来应对。首先，要接受当前的状态，并不断努力调整自己的生活方式和养生习惯，以提升自己的能量水平。尽管当前的状态可能不尽如人意，但要相信时间和努力会带来好转。入墓并不意味着永久的困境，而是一个临时的阶段，因此，要保持乐观的心态，相信自己的能力，坚持不懈地努力，通过不断的积蓄能量，耐心等待时机的到来。"},"is_kongwang":"0","is_maxing":"0","yingan":"己"},{"shenpan":{"bashen":"太阴"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天任","sanqiliuyi":"丙","bashen":"","yuelingwangshuai":"月囚","wangshuai":"废","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"旺","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"乙","sanqiliuyi_changsheng":"生","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"生门","yuelingwangshuai":"月死","wangshuai":"相","is_bamen_menpo":"0"},"description":{"gong_ju":"大吉局","gong_ju_desc":"大吉象征着吉祥如意、顺利发展的情景。它代表着事事顺利、一帆风顺的状态，预示着好运连连、机遇不断。大吉的状态是积极向上的，充满了活力和动力，适宜行动。","luo_gong_desc":"生门象征着远行以及婚姻嫁娶恋爱相关；因此生门落离宫，在远行方面，您的出行计划可能会顺利进行，遇到的挑战和困难会得到圆满解决，行程会非常愉快和顺利。您可能会享受到美好的出行体验，感受到心灵的宁静和愉悦，远离压力和烦恼。这种状态有助于您放松身心，享受出行中的每一刻。婚姻嫁娶恋爱方面，感情关系将会非常顺利和美好。无论是正在寻求爱情的单身者，还是已经拥有美好感情的伴侣，都可能会经历一段愉快和充满幸福的时光。这种状态下，您可能会感受到与伴侣之间的深厚情感和默契，关系会更加稳固和美满，建议您珍惜这段美好的感情。保持沟通和理解，共同创造更加美好的未来。"},"is_kongwang":"0","is_maxing":"0","yingan":"丁"},{"shenpan":{"bashen":"六合"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天冲","sanqiliuyi":"庚","bashen":"","yuelingwangshuai":"月相","wangshuai":"休","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"冠临","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"己","sanqiliuyi_changsheng":"冠沐","is_sanqiliuyi_jixing":"1","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"伤门","yuelingwangshuai":"月旺","wangshuai":"囚","is_bamen_menpo":"1"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征着能量的隐藏或限制，整体状态不佳，但是状态并不一定是负面的，它可能意味着当前的能量状态较低迷，但并不代表永久的困境。在某些情况下，可能意味着暂时隐藏或积蓄能量，等待时机以发挥更大的作用。","luo_gong_desc":"伤门象征着你所面临的困难和挑战；因此伤门落坤宫，你的困难和挑战困难来自于你自己的内心状态，您当前内心的能量状态较低迷，你在面对困难和挫折时，会感到无助和迷茫，难以找到解决问题的方法。但是这种状态是暂时性的，可能意味着您需要更多的时间来调整和恢复，以应对挑战。您可能需要寻求内心的平静和坚定，积极调整心态，以期待更好的时机到来。此外，也可能意味着您需要更多的自我反思和内省，以认识和解决内心的困扰，从而重新获得能量和动力，应对困难和挑战。因此，建议您保持耐心和坚强，相信自己的内在力量，积极寻找内心的平静和支持，以克服当前的困境。"},"is_kongwang":"0","is_maxing":"0","yingan":"乙"},{"shenpan":{"bashen":"白虎"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天辅","sanqiliuyi":"辛","bashen":"","yuelingwangshuai":"月相","wangshuai":"囚","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"临","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"丁","sanqiliuyi_changsheng":"生","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"杜门","yuelingwangshuai":"月旺","wangshuai":"死","is_bamen_menpo":"0"},"description":{"gong_ju":"受制局","gong_ju_desc":"受制象征着受到某种限制或束，为八门之一被所落之宫所克，代表着人事关系无法发挥作用。受制不影响一件事最终的成败，它只是一种状态表现，受制的情况下，通常凶门受制反而变吉，吉门受制可能会转化为不利的结果。","luo_gong_desc":"杜门象征着堵塞和藏匿的意思；因此杜门落兑宫，吉门受制，事情会变得不太顺利。这种限制可能来自外部环境或他人的行为，使得您在处理事务时遇到阻碍或困难。然而，尽管事情变得不太顺利，但藏匿一段时间后可能会出现转机。在藏匿期间，您有机会进行自我反省和调整，寻找解决问题的方法，并且有时间远离外界的干扰，平复内心的情绪。这种自我休养和调整可以帮助您重新审视问题，找到突破口，并重新树立信心和决心。因此，随着藏匿期间的积极努力，您会逐渐发现事情开始有所转机，使得原本不顺利的局面开始朝着更好的方向发展。"},"is_kongwang":"0","is_maxing":"0","yingan":"壬"},{"shenpan":{"bashen":"玄武"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天英","sanqiliuyi":"乙","bashen":"","yuelingwangshuai":"月废","wangshuai":"休","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"墓死","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"1","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"癸","sanqiliuyi_changsheng":"衰旺","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"景门","yuelingwangshuai":"月相","wangshuai":"囚","is_bamen_menpo":"1"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征着能量的隐藏或限制，整体状态不佳，但是状态并不一定是负面的，它可能意味着当前的能量状态较低迷，但并不代表永久的困境。在某些情况下，可能意味着暂时隐藏或积蓄能量，等待时机以发挥更大的作用。","luo_gong_desc":"景门代表考试、升学，学业相关；因此景门落乾宫，这可能意味着你当前的学业状态并不是最为充盈或充满活力的，可能是一个暂时的低迷期，需要你调整自己的心态和行动。在这个阶段，你会感觉到一些挫折或困难，你也许需要在学业上花费更多的时间和精力来准备自己。这可能包括更多的自我反思和学习方法的调整。尽管当前可能感觉到一些困难，但你仍然有机会在未来展现出更大的潜力。因此，要保持乐观的心态，并且持续努力学习。记住，挑战是成长的一部分，而且它们通常为成功铺平道路，通过克服眼前的困难，你将会变得更加强大。"},"is_kongwang":"0","is_maxing":"0","yingan":"辛"},{"shenpan":{"bashen":""},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"","sanqiliuyi":"","bashen":"","yuelingwangshuai":"","wangshuai":"","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"壬","sanqiliuyi_changsheng":"","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"中门","yuelingwangshuai":"","wangshuai":"","is_bamen_menpo":"0"},"description":{"gong_ju":"未知局","gong_ju_desc":"不做解析","luo_gong_desc":"中门并非八门之一，而是甲的隐身地，故为遁甲，甲是元首，中宫是首都，是大后方，最安全的地方，戒备森严。甲静静地隐蔽在中门内，却能动洞察四面八方——运筹帷幄之中，决胜千里之外。故主静止，封闭，停止，神圣不可侵犯等，因此不做解析。"},"is_kongwang":"0","is_maxing":"0","yingan":"庚"}]}}';
        $demo_json_zh_tw = '{"errcode":0,"errmsg":"请求成功","notice":"本次测算结果仅供娱乐使用，请勿用于封建迷信和违法用途。","data":{"name":"測試數據","sex":"坤造","gongli":"2025年03月15日15時12分","nongli":"2025年二月十六日申時","sizhu_info":{"year_gan":"乙","year_zhi":"巳","month_gan":"己","month_zhi":"卯","day_gan":"癸","day_zhi":"未","hour_gan":"庚","hour_zhi":"申"},"xunkong_info":{"year_xunkong":"寅卯空","month_xunkong":"申酉空","day_xunkong":"申酉空","hour_xunkong":"子丑空"},"xunshou_info":{"year_xunshou":"甲辰","month_xunshou":"甲戌","day_xunshou":"甲戌","hour_xunshou":"甲寅"},"zhifu_info":{"zhifu_name":"天心","zhifu_luogong":"三","zhishi_name":"開門","zhishi_luogong":"三"},"fushou":"癸","xunshou":"甲寅癸","dunju":"上元陽遁一局","dingju":"拆補法定局","panlei":"转盘奇門","maxing_info":{"maxing_name":"馬星寅","maxing_luogong":"八"},"kongwang_info":{"kongwang_name":"子丑空","kongwang_luogong":"一,八"},"jieqi_pre":"公历 2025-03-05 16:07:02 驚蟄","jieqi_next":"公历 2025-03-20 17:01:14 春分","gong_pan":[{"shenpan":{"bashen":"九地"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"壬","jiuxing_tianqin":"禽","jiuxing":"天芮","sanqiliuyi":"己","bashen":"","yuelingwangshuai":"月囚","wangshuai":"休","tianqin_sanqiliuyi_changsheng":"旺","sanqiliuyi_changsheng":"絕","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"戊","sanqiliuyi_changsheng":"胎","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"死門","yuelingwangshuai":"死","wangshuai":"囚","is_bamen_menpo":"1"},"description":{"gong_ju":"門迫局","gong_ju_desc":"門迫通常被認為是不利的，因為它象征著能量的削弱和對宮位所有符號的傷害。遇門迫，則表示人事關系阻礙事物的發展，比如想做某件事，但是有家裏人或朋友反對拒絕。也表示個人對當前環境的滿意度不高，希望改變現狀。","luo_gong_desc":"死門代表過去的一些負面，消極的情緒相關；因此死門落坎宮，你可能在過去的一段時間，感到沮喪和失望，因為人際關系的阻礙阻礙了你想要做的事情。感到自己處於一種被束縛和限製的狀態。以及對當前環境的滿意度不高，渴望改變現狀，但卻無法輕易改變周圍的情況，導致情緒低落和焦慮。然而，即使面臨困難，仍然可以通過積極的態度和努力克服障礙，尋找解決問題的方法，相信通過堅持不懈的努力，最終會走出困境，迎來好的結果。"},"is_kongwang":"1","is_maxing":"0","yingan":"丙"},{"shenpan":{"bashen":"九天"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天柱","sanqiliuyi":"丁","bashen":"","yuelingwangshuai":"月休","wangshuai":"廢","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"墓死","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"1","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"丙","sanqiliuyi_changsheng":"養生","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"驚門","yuelingwangshuai":"月囚","wangshuai":"相","is_bamen_menpo":"0"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征著能量的隱藏或限製，整體狀態不佳，但是狀態並不一定是負面的，它可能意味著當前的能量狀態較低迷，但並不代表永久的困境。在某些情況下，可能意味著暫時隱藏或積蓄能量，等待時機以發揮更大的作用。","luo_gong_desc":"驚門代表外部環境出現的突發的變化或不穩定因素，會給人帶來驚訝、不安或混亂的情緒；因此驚門落艮宮，外部環境突然出現的變化或不穩定因素可能會打破你的生活中這種平衡，感情發展過於緩慢可能會給你帶去不安或混亂的情緒，這個可能源於各種因素，如溝通不暢、情感不匹配、外部壓力等，導致關系發展的停滯或緩慢。在入墓局中，可能暗示著暫時的停滯，可能需要時間來處理和調整情感的發展。這種情況下，你可能需要順其自然，不要強求，讓事情自然發展，尋找內在的平衡和調和。"},"is_kongwang":"1","is_maxing":"1","yingan":"癸"},{"shenpan":{"bashen":"值符"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天心","sanqiliuyi":"癸","bashen":"","yuelingwangshuai":"月休","wangshuai":"休","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"生","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"庚","sanqiliuyi_changsheng":"胎","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"開門","yuelingwangshuai":"月囚","wangshuai":"囚","is_bamen_menpo":"1"},"description":{"gong_ju":"門迫局","gong_ju_desc":"門迫通常被認為是不利的，因為它象征著能量的削弱和對宮位所有符號的傷害。在實際應用中，門迫可能預示著人事方面的困難，如合作難以達成、或其他不利的情況。也表示個人對當前環境的滿意度不高，希望改變現狀。","luo_gong_desc":"開門象征機遇、財富與事業的信息；因此開門落震宮，機遇方面，可能會出現難以把握的情況，機會不再頻繁出現，需要更多的耐心和努力去尋找。財富方面，可能會遇到資金周轉不靈、投資收益不佳等問題，需要謹慎處理財務，避免損失。在事業方面，可能會遭遇人際關系的挑戰，合作關系難以達成，工作進展受阻。然而，盡管面臨困難，門迫也暗示著一種轉變的需求，個人對現狀的不滿意可能促使你尋求改變，積極調整策略、改善環境，從而重新開啟機遇、財富與事業的新篇章。通過審慎的計劃和果斷的行動，你依然能夠克服挑戰，實現自己的目標和願景。"},"is_kongwang":"0","is_maxing":"0","yingan":"戊"},{"shenpan":{"bashen":"螣蛇"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天蓬","sanqiliuyi":"戊","bashen":"","yuelingwangshuai":"月旺","wangshuai":"旺","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"冠臨","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"辛","sanqiliuyi_changsheng":"墓死","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"1"},"renpan":{"bamen":"休門","yuelingwangshuai":"月休","wangshuai":"休","is_bamen_menpo":"0"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征著能量的隱藏或限製，整體狀態不佳，但是狀態並不一定是負面的，它可能意味著當前的能量狀態較低迷，但並不代表永久的困境。在某些情況下，可能意味著暫時隱藏或積蓄能量，等待時機以發揮更大的作用。","luo_gong_desc":"休門象征著休息、寧靜、安逸，常與養生、健康相關；因此休門落巽宮，你的健康運勢可能會呈現出能量的隱藏或限製的情況。這意味著當前的能量狀態較低迷，整體狀態不佳，在這種情況下，重要的是要認識到自己的能量狀態，並采取適當的措施來應對。首先，要接受當前的狀態，並不斷努力調整自己的生活方式和養生習慣，以提升自己的能量水平。盡管當前的狀態可能不盡如人意，但要相信時間和努力會帶來好轉。入墓並不意味著永久的困境，而是一個臨時的階段，因此，要保持樂觀的心態，相信自己的能力，堅持不懈地努力，通過不斷的積蓄能量，耐心等待時機的到來。"},"is_kongwang":"0","is_maxing":"0","yingan":"己"},{"shenpan":{"bashen":"太陰"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天任","sanqiliuyi":"丙","bashen":"","yuelingwangshuai":"月囚","wangshuai":"廢","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"旺","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"乙","sanqiliuyi_changsheng":"生","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"生門","yuelingwangshuai":"月死","wangshuai":"相","is_bamen_menpo":"0"},"description":{"gong_ju":"大吉局","gong_ju_desc":"大吉象征著吉祥如意、順利發展的情景。它代表著事事順利、一帆風順的狀態，預示著好運連連、機遇不斷。大吉的狀態是積極向上的，充滿了活力和動力，適宜行動。","luo_gong_desc":"生門象征著遠行以及婚姻嫁娶戀愛相關；因此生門落離宮，在遠行方面，您的出行計劃可能會順利進行，遇到的挑戰和困難會得到圓滿解決，行程會非常愉快和順利。您可能會享受到美好的出行體驗，感受到心靈的寧靜和愉悅，遠離壓力和煩惱。這種狀態有助於您放松身心，享受出行中的每一刻。婚姻嫁娶戀愛方面，感情關系將會非常順利和美好。無論是正在尋求愛情的單身者，還是已經擁有美好感情的伴侶，都可能會經歷一段愉快和充滿幸福的時光。這種狀態下，您可能會感受到與伴侶之間的深厚情感和默契，關系會更加穩固和美滿，建議您珍惜這段美好的感情。保持溝通和理解，共同創造更加美好的未來。"},"is_kongwang":"0","is_maxing":"0","yingan":"丁"},{"shenpan":{"bashen":"六合"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天沖","sanqiliuyi":"庚","bashen":"","yuelingwangshuai":"月相","wangshuai":"休","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"冠臨","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"己","sanqiliuyi_changsheng":"冠沐","is_sanqiliuyi_jixing":"1","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"傷門","yuelingwangshuai":"月旺","wangshuai":"囚","is_bamen_menpo":"1"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征著能量的隱藏或限製，整體狀態不佳，但是狀態並不一定是負面的，它可能意味著當前的能量狀態較低迷，但並不代表永久的困境。在某些情況下，可能意味著暫時隱藏或積蓄能量，等待時機以發揮更大的作用。","luo_gong_desc":"傷門象征著你所面臨的困難和挑戰；因此傷門落坤宮，你的困難和挑戰困難來自於你自己的內心狀態，您當前內心的能量狀態較低迷，你在面對困難和挫折時，會感到無助和迷茫，難以找到解決問題的方法。但是這種狀態是暫時性的，可能意味著您需要更多的時間來調整和恢復，以應對挑戰。您可能需要尋求內心的平靜和堅定，積極調整心態，以期待更好的時機到來。此外，也可能意味著您需要更多的自我反思和內省，以認識和解決內心的困擾，從而重新獲得能量和動力，應對困難和挑戰。因此，建議您保持耐心和堅強，相信自己的內在力量，積極尋找內心的平靜和支持，以克服當前的困境。"},"is_kongwang":"0","is_maxing":"0","yingan":"乙"},{"shenpan":{"bashen":"白虎"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天輔","sanqiliuyi":"辛","bashen":"","yuelingwangshuai":"月相","wangshuai":"囚","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"臨","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"丁","sanqiliuyi_changsheng":"生","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"杜門","yuelingwangshuai":"月旺","wangshuai":"死","is_bamen_menpo":"0"},"description":{"gong_ju":"受製局","gong_ju_desc":"受製象征著受到某種限製或束，為八門之一被所落之宮所克，代表著人事關系無法發揮作用。受製不影響一件事最終的成敗，它只是一種狀態表現，受製的情況下，通常兇門受製反而變吉，吉門受製可能會轉化為不利的結果。","luo_gong_desc":"杜門象征著堵塞和藏匿的意思；因此杜門落兌宮，吉門受製，事情會變得不太順利。這種限製可能來自外部環境或他人的行為，使得您在處理事務時遇到阻礙或困難。然而，盡管事情變得不太順利，但藏匿一段時間後可能會出現轉機。在藏匿期間，您有機會進行自我反省和調整，尋找解決問題的方法，並且有時間遠離外界的幹擾，平復內心的情緒。這種自我休養和調整可以幫助您重新審視問題，找到突破口，並重新樹立信心和決心。因此，隨著藏匿期間的積極努力，您會逐漸發現事情開始有所轉機，使得原本不順利的局面開始朝著更好的方向發展。"},"is_kongwang":"0","is_maxing":"0","yingan":"壬"},{"shenpan":{"bashen":"玄武"},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"天英","sanqiliuyi":"乙","bashen":"","yuelingwangshuai":"月廢","wangshuai":"休","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"墓死","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"1","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"癸","sanqiliuyi_changsheng":"衰旺","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"景門","yuelingwangshuai":"月相","wangshuai":"囚","is_bamen_menpo":"1"},"description":{"gong_ju":"入墓局","gong_ju_desc":"入墓象征著能量的隱藏或限製，整體狀態不佳，但是狀態並不一定是負面的，它可能意味著當前的能量狀態較低迷，但並不代表永久的困境。在某些情況下，可能意味著暫時隱藏或積蓄能量，等待時機以發揮更大的作用。","luo_gong_desc":"景門代表考試、升學，學業相關；因此景門落乾宮，這可能意味著你當前的學業狀態並不是最為充盈或充滿活力的，可能是一個暫時的低迷期，需要你調整自己的心態和行動。在這個階段，你會感覺到一些挫折或困難，你也許需要在學業上花費更多的時間和精力來準備自己。這可能包括更多的自我反思和學習方法的調整。盡管當前可能感覺到一些困難，但你仍然有機會在未來展現出更大的潛力。因此，要保持樂觀的心態，並且持續努力學習。記住，挑戰是成長的一部分，而且它們通常為成功鋪平道路，通過克服眼前的困難，你將會變得更加強大。"},"is_kongwang":"0","is_maxing":"0","yingan":"辛"},{"shenpan":{"bashen":""},"tianpan":{"jiuxing_tianqin_sanqiliuyi":"","jiuxing_tianqin":"","jiuxing":"","sanqiliuyi":"","bashen":"","yuelingwangshuai":"","wangshuai":"","tianqin_sanqiliuyi_changsheng":"","sanqiliuyi_changsheng":"","is_sanqiliuyi_jixing":"0","is_tianqin_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0","is_tianqin_sanqiliuyi_rumu":"0"},"dipan":{"bashen":"","bagua":"","sanqiliuyi":"壬","sanqiliuyi_changsheng":"","is_sanqiliuyi_jixing":"0","is_sanqiliuyi_rumu":"0"},"renpan":{"bamen":"中門","yuelingwangshuai":"","wangshuai":"","is_bamen_menpo":"0"},"description":{"gong_ju":"未知局","gong_ju_desc":"不做解析","luo_gong_desc":"中門並非八門之一，而是甲的隱身地，故為遁甲，甲是元首，中宮是首都，是大後方，最安全的地方，戒備森嚴。甲靜靜地隱蔽在中門內，卻能動洞察四面八方——運籌帷幄之中，決勝千裏之外。故主靜止，封閉，停止，神聖不可侵犯等，因此不做解析。"},"is_kongwang":"0","is_maxing":"0","yingan":"庚"}]}}';

        if ($lang == 'zh-tw') {
            $demo_json = $demo_json_zh_tw;
        } else {
            $demo_json = $demo_json_zh_cn;
        }

        // 2. 解析为 PHP 数组
        $demo_array_json = json_decode($demo_json, true);

        // 3. 【核心提取】剥离外层的 errcode 状态，只提取 data 节点内容
        $data = $demo_array_json['data'] ?? [];

        // 5. 返回处理好的干净数据给 process_api_data
        return $data;
    }
